// Vértice Distribuciones — mock data

export interface Cliente {
  id: string; nombre: string; empresa: string; email: string; telefono: string;
  sector: string; estado: 'activo' | 'inactivo' | 'vip'; pedidos: number;
  ingresos_total: number; ultimo_contacto: string; ciudad: string;
}

export interface Lead {
  id: string; nombre: string; empresa: string;
  canal: 'LinkedIn' | 'Referido' | 'Web' | 'Evento' | 'Cold Email' | 'Feria';
  etapa: 'nuevo' | 'contactado' | 'calificado' | 'reunion_agendada' | 'propuesta_enviada' | 'perdido';
  score: number; valor_estimado: number; responsable: string; fecha: string;
}

export interface Pedido {
  id: string; cliente: string; empresa: string; fecha: string;
  monto: number; estado: 'pendiente' | 'en_ruta' | 'entregado' | 'cancelado';
  productos: number; ciudad_destino: string;
}

export interface Producto {
  id: string; nombre: string; categoria: string; sku: string;
  precio_unitario: number; stock: number; stock_minimo: number;
  proveedor: string; unidad: string;
}

